xpath.script:

(function() {
    function initShopFilters() {
        if (!window.location.pathname.startsWith('/shop')) return;

        var params = new URLSearchParams(window.location.search);

        // --- 1. RESTORE LOKASI ---
        var lokasiVal = params.get('lokasi') || '';
        if (lokasiVal) {
            var r = document.querySelector('input[name="lokasi"][value="' + lokasiVal + '"]');
            if (r) r.checked = true;
        }

        // --- 2. RESTORE KONDISI (URL: new/used → radio: baru/bekas) ---
        var kondisiVal = params.get('kondisi') || '';
        if (kondisiVal) {
            var map = { 'new': 'baru', 'used': 'bekas' };
            var rv = map[kondisiVal] || kondisiVal;
            var kr = document.querySelector('input[name="kondisi"][value="' + rv + '"]');
            if (kr) kr.checked = true;
        }
        if (!kondisiVal) {
            var allK = document.querySelectorAll('input[name="kondisi"]');
            for (var i = 0; i < allK.length; i++) allK[i].checked = false;
        }

        // --- 3. PRICE SLIDER ---
        var minSlider = document.getElementById('min-price');
        var maxSlider = document.getElementById('max-price');
        var minTooltip = document.getElementById('min-tooltip');
        var maxTooltip = document.getElementById('max-tooltip');
        var sliderTrack = document.getElementById('slider-track');
        var odooMin = document.getElementById('odoo-min-price');
        var odooMax = document.getElementById('odoo-max-price');

        if (minSlider && maxSlider) {
            var urlMin = parseInt(params.get('ut_min_price') || '0');
            var urlMax = parseInt(params.get('ut_max_price') || '0');
            if (urlMin > 0) minSlider.value = Math.round(urlMin / 1000);
            if (urlMax > 0) maxSlider.value = Math.round(urlMax / 1000);

            function updateSlider(e) {
                var minVal = parseInt(minSlider.value);
                var maxVal = parseInt(maxSlider.value);
                if (minVal >= maxVal) {
                    if (e && e.target && e.target.id === 'min-price') {
                        minSlider.value = maxVal - 1;
                        minVal = maxVal - 1;
                    } else {
                        maxSlider.value = minVal + 1;
                        maxVal = minVal + 1;
                    }
                }
                var minPct = (minVal / parseInt(minSlider.max)) * 100;
                var maxPct = (maxVal / parseInt(maxSlider.max)) * 100;
                if (sliderTrack) {
                    sliderTrack.style.left = minPct + '%';
                    sliderTrack.style.right = (100 - maxPct) + '%';
                }
                if (minTooltip) {
                    minTooltip.style.left = minPct + '%';
                    minTooltip.innerText = minVal + ' K';
                }
                if (maxTooltip) {
                    maxTooltip.style.left = maxPct + '%';
                    maxTooltip.innerText = maxVal + ' K';
                }
                if (odooMin) odooMin.value = minVal * 1000;
                if (odooMax) odooMax.value = maxVal * 1000;
            }
            minSlider.addEventListener('input', updateSlider);
            maxSlider.addEventListener('input', updateSlider);
            updateSlider();
        }

        // --- 4. SORT BAR ---
        var sortBar = document.getElementById('ut-sort-bar');
        var currentSort = params.get('sort') || 'terkait';
        if (sortBar) {
            var pills = sortBar.querySelectorAll('[data-sort]');
            for (var j = 0; j < pills.length; j++) {
                (function(pill) {
                    var sk = pill.getAttribute('data-sort');
                    if (sk === currentSort) {
                        pill.style.backgroundColor = '#1a1a1a';
                        pill.style.color = '#fff';
                        pill.style.fontWeight = '600';
                    }
                    pill.addEventListener('click', function() {
                        var p = new URLSearchParams(window.location.search);
                        p.set('sort', sk);
                        window.location.href = '/shop?' + p.toString();
                    });
                })(pills[j]);
            }
        }

        // --- 5. SIMPAN BUTTON ---
        var simpanBtn = document.getElementById('ut-btn-simpan');
        if (simpanBtn) {
            simpanBtn.addEventListener('click', function(e) {
                e.preventDefault();
                var p = new URLSearchParams();
                var s = params.get('search');
                if (s) p.set('search', s);
                var so = params.get('sort');
                if (so) p.set('sort', so);

                var lc = document.querySelector('input[name="lokasi"]:checked');
                if (lc && lc.value) p.set('lokasi', lc.value);

                var mnP = odooMin ? parseInt(odooMin.value) : 0;
                var mxP = odooMax ? parseInt(odooMax.value) : 0;
                if (mnP > 0) p.set('ut_min_price', mnP);
                if (mxP > 0) p.set('ut_max_price', mxP);

                var kc = document.querySelector('input[name="kondisi"]:checked');
                if (kc && kc.value) {
                    var km = { 'baru': 'new', 'bekas': 'used' };
                    p.set('kondisi', km[kc.value] || kc.value);
                }
                window.location.href = '/shop?' + p.toString();
            });
        }

        // --- 6. BATAL BUTTON ---
        var batalBtn = document.getElementById('ut-btn-batal');
        if (batalBtn) {
            batalBtn.addEventListener('click', function() {
                window.location.reload();
            });
        }

        // --- 7. RESET BUTTON ---
        var resetBtn = document.getElementById('ut-btn-reset');
        if (resetBtn) {
            resetBtn.addEventListener('click', function() {
                var p = new URLSearchParams();
                var s = params.get('search');
                if (s) p.set('search', s);
                var qs = p.toString();
                window.location.href = '/shop' + (qs ? '?' + qs : '');
            });
        }
    }

    // Run when DOM is ready (handle both cases)
    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', initShopFilters);
    } else {
        initShopFilters();
    }
})();
